const fetch = require('node-fetch'); // You might need to 'npm install node-fetch'
// Alternatively, use built-in 'https' module for Node.js if node-fetch is not desired.

// --- IMPORTANT: Replace with your actual Cloud Function URL ---
const CLOUD_FUNCTION_URL = "https://clearanonymoususers-kx7ucvnwtq-uc.a.run.app"; // Replace with your actual URL

// --- IMPORTANT: Replace with a valid ID Token from an authenticated admin user ---
// How to get an ID token:
// 1. Log in to your Firebase project in the browser as an admin user.
// 2. Open your browser's developer console (F12).
// 3. In the console, run: `firebase.auth().currentUser.getIdToken().then(token => console.log(token))`
// 4. Copy the token and paste it here, or set it as an environment variable named ADMIN_ID_TOKEN.
const ADMIN_ID_TOKEN = process.env.ADMIN_ID_TOKEN || 'YOUR_ADMIN_ID_TOKEN_HERE';

async function callClearAnonymousUsers() {
  if (ADMIN_ID_TOKEN === 'YOUR_ADMIN_ID_TOKEN_HERE' || !ADMIN_ID_TOKEN) {
    console.error('Error: ADMIN_ID_TOKEN is not set. Please get a valid ID token as described in the script comments.');
    return;
  }

  try {
    console.log('Calling clearAnonymousUsers Cloud Function...');
    const response = await fetch(CLOUD_FUNCTION_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${ADMIN_ID_TOKEN}`,
      },
      // You might need to send an empty body or a specific payload if the function expects one
      body: JSON.stringify({}), 
    });

    if (!response.ok) {
      const errorData = await response.json();
      throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
    }

    const result = await response.json();
    console.log('Cloud Function Result:', result);
  } catch (error) {
    console.error('Error calling Cloud Function:', error);
  }
}

callClearAnonymousUsers();

