      if (deleteResult.failureCount > 0) {
        console.error(`Failed to delete ${deleteResult.failureCount} anonymous user accounts:`);
        deleteResult.errors.forEach(err => {
          console.error(`  User UID: ${err.uid}, Error: ${err.error.message}`);
        });
      }
    } else {
      console.log('No anonymous user accounts found to delete.');
    }

    process.exit(0);
  } catch (error) {
    console.error('Error clearing anonymous Firebase Auth users:', error);
    process.exit(1);
  }
}

clearAnonymousAuthUsers();
